package main

import (
	"fmt"
	"os"
	"sort"
	"strings"

	goGit "github.com/go-git/go-git/v6"
)

func cmdStatus(args []string) int {
	var (
		porcelain    bool
		short        bool
		branch       bool
		showUntracked = "normal" // "all", "normal", "no"
	)

	for _, a := range args {
		switch a {
		case "--porcelain", "--porcelain=v1":
			porcelain = true
		case "-s", "--short":
			short = true
		case "--no-short":
			short = false
		case "-b", "--branch":
			branch = true
		case "--no-branch":
			branch = false
		case "-z":
			// NUL-terminated, ignored for now
		case "-u", "--untracked-files", "--untracked-files=all", "-uall":
			showUntracked = "all"
		case "-uno", "--untracked-files=no":
			showUntracked = "no"
		case "-unormal", "--untracked-files=normal":
			showUntracked = "normal"
		case "--column", "--no-column":
			// accepted, ignored (we don't columnize)
		case "-v":
			// verbose — would need diff, ignored for now
		default:
			if strings.HasPrefix(a, "--column=") {
				// accepted, ignored
			}
		}
	}

	// Check status.short and status.branch config options.
	cfg, cfgErr := readRawConfig()
	if cfgErr == nil {
		if !porcelain {
			for _, s := range cfg.Sections {
				if !s.IsName("status") {
					continue
				}
				if s.HasOption("short") {
					v := strings.ToLower(s.Option("short"))
					if v == "true" || v == "yes" || v == "on" || v == "1" {
						short = true
					}
				}
				if s.HasOption("branch") {
					v := strings.ToLower(s.Option("branch"))
					if v == "true" || v == "yes" || v == "on" || v == "1" {
						if !short && !porcelain {
							// status.branch only applies to short format
						} else {
							branch = true
						}
					}
				}
			}
		}
	}

	// Override: explicit -s/--short on the command line re-scans args
	// (already handled above via the flag parser)

	repo := openRepoOrDie()
	wt, err := repo.Worktree()
	if err != nil {
		fmt.Fprintf(os.Stderr, "fatal: %s\n", err)
		return 128
	}

	status, err := wt.Status()
	if err != nil {
		fmt.Fprintf(os.Stderr, "fatal: %s\n", err)
		return 128
	}

	if porcelain || short {
		if branch {
			printShortBranch(repo)
		}
		printShortStatus(status, showUntracked)
		return 0
	}

	// Long format.
	return printLongStatus(repo, status, showUntracked)
}

// printShortBranch prints the "## branch...upstream" header for -s -b.
func printShortBranch(repo *goGit.Repository) {
	head, err := repo.Head()
	if err != nil || !head.Name().IsBranch() {
		fmt.Println("## HEAD (no branch)")
		return
	}
	branchName := head.Name().Short()

	// Try to find upstream tracking branch.
	cfg, err := readRawConfig()
	if err != nil {
		fmt.Printf("## %s\n", branchName)
		return
	}

	remote, merge := "", ""
	for _, s := range cfg.Sections {
		if !s.IsName("branch") {
			continue
		}
		for _, ss := range s.Subsections {
			if ss.IsName(branchName) {
				remote = ss.Option("remote")
				merge = ss.Option("merge")
			}
		}
	}

	if remote == "" || merge == "" {
		fmt.Printf("## %s\n", branchName)
		return
	}

	// Convert merge ref (refs/heads/foo) to remote tracking ref (refs/remotes/origin/foo).
	upstream := strings.TrimPrefix(merge, "refs/heads/")
	trackingDisplay := remote + "/" + upstream

	fmt.Printf("## %s...%s\n", branchName, trackingDisplay)
}

// printShortStatus prints porcelain/short format, with tracked changes sorted
// before untracked entries (matching git's output order).
func printShortStatus(status goGit.Status, showUntracked string) {
	var tracked, untracked []string
	for p, s := range status {
		if s.Staging == goGit.Untracked && s.Worktree == goGit.Untracked {
			untracked = append(untracked, p)
		} else if s.Staging != goGit.Unmodified || s.Worktree != goGit.Unmodified {
			tracked = append(tracked, p)
		}
	}
	sort.Strings(tracked)
	sort.Strings(untracked)

	for _, p := range tracked {
		s := status[p]
		fmt.Printf("%c%c %s\n", byte(s.Staging), byte(s.Worktree), p)
	}
	if showUntracked != "no" {
		for _, p := range untracked {
			fmt.Printf("?? %s\n", p)
		}
	}
}

// printLongStatus prints git's default long status format with sections.
func printLongStatus(repo *goGit.Repository, status goGit.Status, showUntracked string) int {
	head, _ := repo.Head()
	if head != nil && head.Name().IsBranch() {
		fmt.Printf("On branch %s\n", head.Name().Short())
	} else if head != nil {
		fmt.Printf("HEAD detached at %s\n", head.Hash().String()[:7])
	}

	// Categorize files.
	var staged, unstaged, untracked []string
	for p, s := range status {
		if s.Staging != goGit.Unmodified && s.Staging != goGit.Untracked {
			staged = append(staged, p)
		}
		if s.Worktree == goGit.Modified || s.Worktree == goGit.Deleted {
			unstaged = append(unstaged, p)
		}
		if s.Staging == goGit.Untracked && s.Worktree == goGit.Untracked {
			untracked = append(untracked, p)
		}
	}
	sort.Strings(staged)
	sort.Strings(unstaged)
	sort.Strings(untracked)

	// Check advice.statusHints config.
	showHints := true
	if rcfg, err := readRawConfig(); err == nil {
		for _, s := range rcfg.Sections {
			if !s.IsName("advice") {
				continue
			}
			if s.HasOption("statusHints") {
				v := strings.ToLower(s.Option("statusHints"))
				if v == "false" || v == "no" || v == "off" || v == "0" {
					showHints = false
				}
			}
		}
	}

	hasStagedSection := len(staged) > 0
	hasUnstagedSection := len(unstaged) > 0
	hasUntrackedSection := showUntracked != "no" && len(untracked) > 0

	if hasStagedSection {
		fmt.Println("Changes to be committed:")
		if showHints {
			fmt.Println("  (use \"git restore --staged <file>...\" to unstage)")
		}
		for _, p := range staged {
			s := status[p]
			fmt.Printf("\t%s%s\n", longStagingPrefix(s.Staging), p)
		}
		fmt.Println()
	}

	if hasUnstagedSection {
		fmt.Println("Changes not staged for commit:")
		if showHints {
			fmt.Println("  (use \"git add <file>...\" to update what will be committed)")
			fmt.Println("  (use \"git restore <file>...\" to discard changes in working directory)")
		}
		for _, p := range unstaged {
			s := status[p]
			fmt.Printf("\t%s%s\n", longWorktreePrefix(s.Worktree), p)
		}
		fmt.Println()
	}

	if hasUntrackedSection {
		fmt.Println("Untracked files:")
		if showHints {
			fmt.Println("  (use \"git add <file>...\" to include in what will be committed)")
		}
		for _, p := range untracked {
			fmt.Printf("\t%s\n", p)
		}
		fmt.Println()
	}

	// Footer message.
	if !hasStagedSection && !hasUnstagedSection && !hasUntrackedSection {
		fmt.Println("nothing to commit, working tree clean")
	} else if !hasStagedSection {
		if hasUnstagedSection {
			fmt.Println("no changes added to commit (use \"git add\" and/or \"git commit -a\")")
		} else if hasUntrackedSection {
			fmt.Println("nothing added to commit but untracked files present (use \"git add\" to track)")
		}
	}

	return 0
}

// longStagingPrefix returns the prefix for a staged file in long format.
func longStagingPrefix(code goGit.StatusCode) string {
	switch code {
	case goGit.Added:
		return "new file:   "
	case goGit.Modified:
		return "modified:   "
	case goGit.Deleted:
		return "deleted:    "
	case goGit.Renamed:
		return "renamed:    "
	case goGit.Copied:
		return "copied:     "
	default:
		return ""
	}
}

// longWorktreePrefix returns the prefix for an unstaged change in long format.
func longWorktreePrefix(code goGit.StatusCode) string {
	switch code {
	case goGit.Modified:
		return "modified:   "
	case goGit.Deleted:
		return "deleted:    "
	default:
		return ""
	}
}

package main

import (
	"bytes"
	"fmt"
	"os"
	"path/filepath"
	"strings"

	format "github.com/go-git/go-git/v6/plumbing/format/config"
)

// configFileOverride is set by -f/--file to operate on an arbitrary config file
// instead of .git/config.
var configFileOverride string

func cmdConfig(args []string) int {
	// Reset per-invocation state.
	configFileOverride = ""

	var (
		scope         string // "local", "global", "system"
		getBool       bool
		getInt        bool
		doGet         bool
		doUnset       bool
		doList        bool
		doAdd         bool
		removeSection string
		key           string
		value         string
		hasValue      bool
	)

	positional := []string{}
	i := 0
	for i < len(args) {
		a := args[i]
		switch a {
		case "--local":
			scope = "local"
		case "--global":
			scope = "global"
		case "--system":
			scope = "system"
		case "--bool":
			getBool = true
		case "--int":
			getInt = true
		case "--get":
			doGet = true
		case "--unset":
			doUnset = true
		case "--list", "-l":
			doList = true
		case "--add":
			doAdd = true
		case "-f", "--file":
			i++
			if i < len(args) {
				configFileOverride = args[i]
			}
		case "--remove-section":
			i++
			if i < len(args) {
				removeSection = args[i]
			}
		case "--default":
			// skip value
			i++
		case "--type":
			// skip value (e.g., --type=bool)
			i++
		case "--null", "-z":
			// accepted, ignored for now
		default:
			if strings.HasPrefix(a, "--file=") {
				configFileOverride = strings.TrimPrefix(a, "--file=")
			} else if strings.HasPrefix(a, "--type=") {
				tp := strings.TrimPrefix(a, "--type=")
				switch tp {
				case "bool":
					getBool = true
				case "int":
					getInt = true
				}
			} else if strings.HasPrefix(a, "--default=") {
				// accepted, ignored
			} else if !strings.HasPrefix(a, "-") {
				positional = append(positional, a)
			}
			// Unknown flags: ignore gracefully.
		}
		i++
	}

	_ = getInt

	if scope == "global" || scope == "system" {
		fmt.Fprintf(os.Stderr, "warning: go-git only supports --local config; --%s is not implemented\n", scope)
	}

	if doList {
		return configList()
	}

	if removeSection != "" {
		return configRemoveSection(removeSection)
	}

	// Parse positional args: git config [--flags] <key> [<value>]
	if doGet && len(positional) > 0 {
		key = positional[0]
	} else if doUnset && len(positional) > 0 {
		key = positional[0]
	} else if len(positional) >= 2 {
		key = positional[0]
		value = positional[1]
		hasValue = true
	} else if len(positional) == 1 {
		key = positional[0]
		if !doGet {
			doGet = true
		}
	}

	if key == "" {
		fmt.Fprintln(os.Stderr, "error: key does not contain a section: ")
		return 2
	}

	if doUnset {
		return configUnset(key)
	}
	if hasValue && !doGet {
		if doAdd {
			return configAdd(key, value)
		}
		return configSet(key, value)
	}
	return configGet(key, getBool)
}

// parseConfigKey splits "section.key" or "section.subsection.key" into parts.
func parseConfigKey(key string) (section, subsection, name string) {
	parts := strings.SplitN(key, ".", 3)
	switch len(parts) {
	case 2:
		return parts[0], "", parts[1]
	case 3:
		return parts[0], parts[1], parts[2]
	default:
		return key, "", ""
	}
}

func configPath() string {
	if configFileOverride != "" {
		return configFileOverride
	}
	return filepath.Join(gitDir(), "config")
}

func readRawConfig() (*format.Config, error) {
	data, err := os.ReadFile(configPath())
	if err != nil {
		if os.IsNotExist(err) {
			return format.New(), nil
		}
		return nil, err
	}
	cfg := format.New()
	if err := format.NewDecoder(bytes.NewReader(data)).Decode(cfg); err != nil {
		return nil, err
	}
	return cfg, nil
}

func writeRawConfig(cfg *format.Config) error {
	var buf bytes.Buffer
	if err := format.NewEncoder(&buf).Encode(cfg); err != nil {
		return err
	}
	return os.WriteFile(configPath(), buf.Bytes(), 0o644)
}

func configGet(key string, asBool bool) int {
	// -c overrides take precedence over on-disk config.
	if globalConfigOverrides != nil {
		if val, ok := globalConfigOverrides[key]; ok {
			return printConfigValue(val, key, asBool)
		}
	}

	cfg, err := readRawConfig()
	if err != nil {
		fmt.Fprintf(os.Stderr, "fatal: unable to read config: %s\n", err)
		return 128
	}

	section, subsection, name := parseConfigKey(key)

	var val string
	var found bool
	for _, s := range cfg.Sections {
		if !s.IsName(section) {
			continue
		}
		if subsection == "" {
			if s.HasOption(name) {
				val = s.Option(name)
				found = true
			}
		} else {
			for _, ss := range s.Subsections {
				if ss.IsName(subsection) && ss.HasOption(name) {
					val = ss.Option(name)
					found = true
				}
			}
		}
	}

	if !found {
		return 1
	}

	return printConfigValue(val, key, asBool)
}

func printConfigValue(val, key string, asBool bool) int {
	if asBool {
		switch strings.ToLower(val) {
		case "true", "yes", "on", "1", "":
			fmt.Println("true")
		case "false", "no", "off", "0":
			fmt.Println("false")
		default:
			fmt.Fprintf(os.Stderr, "fatal: bad boolean config value '%s' for '%s'\n", val, key)
			return 128
		}
	} else {
		fmt.Println(val)
	}
	return 0
}

func configSet(key, value string) int {
	cfg, err := readRawConfig()
	if err != nil {
		fmt.Fprintf(os.Stderr, "fatal: unable to read config: %s\n", err)
		return 128
	}

	section, subsection, name := parseConfigKey(key)
	cfg.SetOption(section, subsection, name, value)

	if err := writeRawConfig(cfg); err != nil {
		fmt.Fprintf(os.Stderr, "fatal: unable to write config: %s\n", err)
		return 128
	}
	return 0
}

func configAdd(key, value string) int {
	cfg, err := readRawConfig()
	if err != nil {
		fmt.Fprintf(os.Stderr, "fatal: unable to read config: %s\n", err)
		return 128
	}

	section, subsection, name := parseConfigKey(key)
	cfg.AddOption(section, subsection, name, value)

	if err := writeRawConfig(cfg); err != nil {
		fmt.Fprintf(os.Stderr, "fatal: unable to write config: %s\n", err)
		return 128
	}
	return 0
}

func configUnset(key string) int {
	cfg, err := readRawConfig()
	if err != nil {
		fmt.Fprintf(os.Stderr, "fatal: unable to read config: %s\n", err)
		return 128
	}

	section, subsection, name := parseConfigKey(key)

	for _, s := range cfg.Sections {
		if !s.IsName(section) {
			continue
		}
		if subsection == "" {
			s.RemoveOption(name)
		} else {
			for _, ss := range s.Subsections {
				if ss.IsName(subsection) {
					ss.RemoveOption(name)
				}
			}
		}
	}

	if err := writeRawConfig(cfg); err != nil {
		fmt.Fprintf(os.Stderr, "fatal: unable to write config: %s\n", err)
		return 128
	}
	return 0
}

func configRemoveSection(name string) int {
	cfg, err := readRawConfig()
	if err != nil {
		fmt.Fprintf(os.Stderr, "fatal: unable to read config: %s\n", err)
		return 128
	}

	// "section.subsection" → remove [section "subsection"]
	// "section"            → remove [section]
	section, subsection, _ := parseConfigKey(name + ".dummy")

	found := false
	if subsection == "" {
		// Remove entire top-level section.
		newSections := make(format.Sections, 0, len(cfg.Sections))
		for _, s := range cfg.Sections {
			if s.IsName(section) {
				found = true
				continue
			}
			newSections = append(newSections, s)
		}
		cfg.Sections = newSections
	} else {
		// Remove a subsection from its parent section.
		for _, s := range cfg.Sections {
			if !s.IsName(section) {
				continue
			}
			newSubs := make(format.Subsections, 0, len(s.Subsections))
			for _, ss := range s.Subsections {
				if ss.IsName(subsection) {
					found = true
					continue
				}
				newSubs = append(newSubs, ss)
			}
			s.Subsections = newSubs
		}
	}

	if !found {
		fmt.Fprintf(os.Stderr, "fatal: no such section: %s\n", name)
		return 128
	}

	if err := writeRawConfig(cfg); err != nil {
		fmt.Fprintf(os.Stderr, "fatal: unable to write config: %s\n", err)
		return 128
	}
	return 0
}

func configList() int {
	cfg, err := readRawConfig()
	if err != nil {
		fmt.Fprintf(os.Stderr, "fatal: unable to read config: %s\n", err)
		return 128
	}

	for _, s := range cfg.Sections {
		for _, o := range s.Options {
			fmt.Printf("%s.%s=%s\n", strings.ToLower(s.Name), o.Key, o.Value)
		}
		for _, ss := range s.Subsections {
			for _, o := range ss.Options {
				fmt.Printf("%s.%s.%s=%s\n", strings.ToLower(s.Name), ss.Name, o.Key, o.Value)
			}
		}
	}

	// Append -c overrides (they take precedence, listed last like real git).
	for k, v := range globalConfigOverrides {
		fmt.Printf("%s=%s\n", k, v)
	}

	return 0
}

