		dir := filepath.Dir(p)
		for dir != "." && dir != "" {
			trackedDirs[dir] = true
			dir = filepath.Dir(dir)
		}
	}

	// For each untracked file, check if its top-level untracked directory
	// can be collapsed.
	collapsed := make(map[string]bool)
	var result []string
	for p := range untrackedSet {
		dir := topUntrackedDir(p, trackedDirs)
		if dir != "" {
			if !collapsed[dir] {
				collapsed[dir] = true
