	}

	// Walk up from the file's directory to find the highest directory
	// that has no tracked files.
	best := ""
	for d := dir; d != "." && d != ""; d = filepath.Dir(d) {
		if trackedDirs[d] {
			break
		}
		best = d
	}
	return best
}

// longStagingPrefix returns the prefix for a staged file in long format.
func longStagingPrefix(code goGit.StatusCode) string {
	switch code {
	case goGit.Added:
		return "new file:   "
	case goGit.Modified:
		return "modified:   "
	case goGit.Deleted:
		return "deleted:    "
	case goGit.Renamed:
		return "renamed:    "
	case goGit.Copied:
		return "copied:     "
	default:
		return ""
	}
}

// longWorktreePrefix returns the prefix for an unstaged change in long format.
func longWorktreePrefix(code goGit.StatusCode) string {
	switch code {
	case goGit.Modified:
		return "modified:   "
	case goGit.Deleted:
		return "deleted:    "
	default:
		return ""
	}
}

