	upstreamHash := trackingRef.Hash()

	if headHash == upstreamHash {
		return 0, 0
	}

	// Collect commits reachable from HEAD.
	headSet := make(map[plumbing.Hash]bool)
	iter, err := repo.Log(&goGit.LogOptions{From: headHash})
