		iter.ForEach(func(c *object.Commit) error {
			headSet[c.Hash] = true
			return nil
		})
	}

	// Collect commits reachable from upstream.
	upstreamSet := make(map[plumbing.Hash]bool)
	iter, err = repo.Log(&goGit.LogOptions{From: upstreamHash})
	if err == nil {
		iter.ForEach(func(c *object.Commit) error {
			upstreamSet[c.Hash] = true
			return nil
		})
