		case "-u", "--untracked-files", "--untracked-files=all", "-uall":
			showUntracked = "all"
		case "-uno", "-ufalse", "--untracked-files=no", "--untracked-files=false":
			showUntracked = "no"
		case "-unormal", "-utrue", "--untracked-files=normal", "--untracked-files=true":
